'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import { Plus } from 'lucide-react'; 

interface FAQItemProps {
  question: string;
  answer: string;
}

const FAQItem: React.FC<FAQItemProps> = ({ question, answer }) => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div 
      className="border-b border-green-light/30 cursor-pointer transition" 
      onClick={() => setIsOpen(!isOpen)}
    >
      <div className="flex justify-between items-center py-5 lg:py-7 px-0">
        <h3 className={`font-body text-lg sm:text-xl font-semibold transition ${isOpen ? 'text-green-main' : 'text-green-dark'}`}>
          {question}
        </h3>
        {/* Анимация вращения иконки */}
        <motion.div
            animate={{ rotate: isOpen ? 45 : 0 }} 
            transition={{ duration: 0.3 }}
            className="text-green-main w-6 h-6 shrink-0"
        >
            <Plus size={24} />
        </motion.div>
      </div>
      
      {/* Анимированный контент (slide down/up) */}
      <motion.div
        initial={false}
        animate={{ height: isOpen ? 'auto' : 0 }}
        transition={{ duration: 0.5, ease: [0.33, 1, 0.68, 1] }} 
        style={{ overflow: 'hidden' }}
      >
        <p className="text-text-medium pb-5 leading-relaxed pr-8">
          {answer}
        </p>
      </motion.div>
    </div>
  );
};

export default FAQItem;